import { Link } from 'react-router-dom';
import { MovieProfile } from '../movie-profile';
import { useEffect, useState } from 'react';
import axios from 'axios';
import { formatLanguageToApi } from '../utils/api-utils';
import { useLanguage } from '../../context/language';
import { MoviesInformation, ResultType } from '.';
import { LoadMoreButton } from '../load-more/load-more-button';

interface MoviesGridParams {
	genre: string;
}

const genre = {
	'genres': [
		{
			'id': 28,
			'name': 'Action'
		},
		{
			'id': 12,
			'name': 'Adventure'
		},
		{
			'id': 16,
			'name': 'Animation'
		},
		{
			'id': 35,
			'name': 'Comedy'
		},
		{
			'id': 80,
			'name': 'Crime'
		},
		{
			'id': 99,
			'name': 'Documentary'
		},
		{
			'id': 18,
			'name': 'Drama'
		},
		{
			'id': 10751,
			'name': 'Family'
		},
		{
			'id': 14,
			'name': 'Fantasy'
		},
		{
			'id': 36,
			'name': 'History'
		},
		{
			'id': 27,
			'name': 'Horror'
		},
		{
			'id': 10402,
			'name': 'Music'
		},
		{
			'id': 9648,
			'name': 'Mystery'
		},
		{
			'id': 10749,
			'name': 'Romance'
		},
		{
			'id': 878,
			'name': 'Science Fiction'
		},
		{
			'id': 10770,
			'name': 'TV Movie'
		},
		{
			'id': 53,
			'name': 'Thriller'
		},
		{
			'id': 10752,
			'name': 'War'
		},
		{
			'id': 37,
			'name': 'Western'
		}
	]
};

export default function MoviesGrid({ genre }: MoviesGridParams) {
	const [movies, setMovies] = useState<MoviesInformation>({ results: [], type: '' });
	const [open, setOpen] = useState<boolean>(false);
	const [genres, setGenres] = useState([]);
	const { language } = useLanguage();

	async function getMovieData() {
		const response = await axios({
			method: 'get',
			url: `https://api.themoviedb.org/3/discover/movie?with_genres=${genre}&api_key=${process.env.REACT_APP_TMDB_API_KEY}&language=${formatLanguageToApi(language)}`,
			headers: { Authorization: `Bearer ${process.env.REACT_APP_TMDB_BEARER_TOKEN}` }
		});
		setMovies(response.data);
	}

	useEffect(() => {
		getMovieData();
	}, []);

	function limitGrid() {
		if(open){
			return movies.results;
		}
		return movies.results.slice(0, 4);
	}

	function handleLoadMoreButton() {
		setOpen(!open);
	}

	function renderTitle() {

	}

	return (
		<div className="grid grid-cols-4 gap-9 object-cover p-7 pt-3">
			{limitGrid().map((movie: ResultType) => {
				return (
					<Link to={`/movie/${movie.id}`} key={movie.id} accessKey="abc">
						<MovieProfile pictureUrl={`https://image.tmdb.org/t/p/w500${movie.poster_path}`} title={movie.title} releaseDate={movie.release_date} />
					</Link>
				);
			})}
			<div className="flex h-10">
				<LoadMoreButton open={open} onClick={handleLoadMoreButton}/>
			</div>
		</div>
	);
}
